def write_csv(filename, data, fieldnames):
    with open(filename, "w", newline="") as f:
        writer = csv.DictWriter(f, fieldnames=fieldnames)
        writer.writeheader()
        writer.writerows(data)


def prepare_orders():
    rows = []
    for o in orders:
        rows.append({
            "order_id":           o["order_id"],
            "customer_name":      o["customer_name"],
            "status":             o["status"],
            "carrier":            o["carrier"],
            "tracking_number":    o["tracking_number"],
            "estimated_delivery": o["estimated_delivery"],
            "items":              json.dumps(o["items"]),
            "shipping_mode":      o["shipping_mode"],
            "order_region":       o["order_region"],
            "order_country":      o["order_country"],
            "order_city":         o["order_city"],
            "market":             o["market"],
            "late_delivery_risk": o["late_delivery_risk"],
            "benefit_per_order":  o["benefit_per_order"],
            "sales_per_customer": o["sales_per_customer"],
            "order_date":         o["order_date"],
        })
    return rows


def prepare_tracking():
    rows = []
    for t in tracking_events:
        rows.append({
            "tracking_number":             t["tracking_number"],
            "carrier":                     t["carrier"],
            "current_location":            t["current_location"],
            "status":                      t["status"],
            "last_update":                 t["last_update"],
            "estimated_delivery":          t["estimated_delivery"],
            "days_for_shipping_real":      t["days_for_shipping_real"],
            "days_for_shipment_scheduled": t["days_for_shipment_scheduled"],
            "delivery_status":             t["delivery_status"],
            "shipping_date":               t["shipping_date"],
            "latitude":                    t["latitude"],
            "longitude":                   t["longitude"],
            "events":                      t["events"],
        })
    return rows


if __name__ == "__main__":
    write_csv(
        "tools/orders.csv",
        prepare_orders(),
        ["order_id", "customer_name", "status", "carrier", "tracking_number",
         "estimated_delivery", "items", "shipping_mode", "order_region",
         "order_country", "order_city", "market", "late_delivery_risk",
         "benefit_per_order", "sales_per_customer", "order_date"]
    )
    write_csv(
        "tools/tracking_events.csv",
        prepare_tracking(),
        ["tracking_number", "carrier", "current_location", "status",
         "last_update", "estimated_delivery", "days_for_shipping_real",
         "days_for_shipment_scheduled", "delivery_status", "shipping_date",
         "latitude", "longitude", "events"]
    )
    print("Generated tools/orders.csv — 25 orders")
    print("Generated tools/tracking_events.csv — 25 tracking records")